// frontend/src/components/vouchers/VoucherPurchase.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import { useAlert } from '../../contexts/AlertContext';
import './Voucher.css';

const VoucherPurchase = () => {
    const { user } = useAuth();
    const alert = useAlert();
    const navigate = useNavigate();

    const [selectedPass, setSelectedPass] = useState('monthly');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    // Pass options for workers
    const passOptions = {
        payg: {
            name: 'Pay-As-You-Go',
            price: 5,
            applications: 1,
            description: 'Single job application',
            icon: '🎫',
            color: '#10B981',
            badge: 'Flexible'
        },
        monthly: {
            name: 'Monthly Pass',
            price: 50,
            applications: 30,
            description: '30 applications over 30 days',
            icon: '📅',
            color: '#FF6B35',
            badge: '🔥 Most Popular',
            savings: 'R1.67 per application'
        },
        annual: {
            name: 'Annual Pass',
            price: 360,
            applications: 'Unlimited',
            description: 'Unlimited applications for a full year',
            icon: '🌟',
            color: '#8B5CF6',
            badge: '✨ Best Value',
            savings: 'Save R240 (40% off)'
        }
    };

    const calculateSavings = () => {
        if (selectedPass === 'annual') {
            return 'Save R240 compared to monthly';
        } else if (selectedPass === 'monthly') {
            return '67% cheaper than pay-as-you-go';
        }
        return '';
    };

    const handlePurchase = async () => {
        setLoading(true);
        setError('');
        setSuccess('');

        try {
            // For demo, only EFT is available
            const response = await api.post('/worker/buy-application-pass', {
                pass_type: selectedPass,
                payment_method: 'eft'
            });

            if (response.data.success) {
                setSuccess(`✅ Successfully purchased ${passOptions[selectedPass].name}!`);
                setTimeout(() => {
                    navigate('/dashboard');
                }, 2000);
            }
        } catch (error) {
            console.error('Purchase error:', error);
            setError(error.response?.data?.message || 'Failed to purchase pass');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="pass-purchase-container">
            <div className="pass-purchase-card">
                <div className="pass-header">
                    <h1>🎫 Worker Application Passes</h1>
                    <p>Choose the perfect plan to start applying for jobs</p>
                </div>

                {error && (
                    <div className="pass-error">
                        <span className="error-icon">⚠️</span>
                        {error}
                    </div>
                )}

                {success && (
                    <div className="pass-success">
                        <span className="success-icon">✅</span>
                        {success}
                    </div>
                )}

                {/* Pass Options Grid */}
                <div className="pass-options-grid">
                    {/* Pay-As-You-Go */}
                    <div 
                        className={`pass-option-card ${selectedPass === 'payg' ? 'selected' : ''}`}
                        onClick={() => setSelectedPass('payg')}
                        style={{ borderColor: selectedPass === 'payg' ? passOptions.payg.color : '#E5E7EB' }}
                    >
                        <div className="pass-option-badge">{passOptions.payg.badge}</div>
                        <div className="pass-option-icon" style={{ background: `${passOptions.payg.color}20` }}>
                            <span style={{ color: passOptions.payg.color }}>{passOptions.payg.icon}</span>
                        </div>
                        <h3>{passOptions.payg.name}</h3>
                        <div className="pass-option-price">R{passOptions.payg.price}</div>
                        <div className="pass-option-applications">
                            <strong>{passOptions.payg.applications}</strong> application
                        </div>
                        <p className="pass-option-description">{passOptions.payg.description}</p>
                        <ul className="pass-features">
                            <li>✓ No commitment</li>
                            <li>✓ Perfect for trying out</li>
                            <li>✓ Valid forever</li>
                        </ul>
                        <button 
                            className={`pass-select-btn ${selectedPass === 'payg' ? 'selected' : ''}`}
                            style={{ 
                                background: selectedPass === 'payg' ? passOptions.payg.color : '#F3F4F6',
                                color: selectedPass === 'payg' ? 'white' : '#4B5563'
                            }}
                        >
                            {selectedPass === 'payg' ? '✓ Selected' : 'Select'}
                        </button>
                    </div>

                    {/* Monthly Pass */}
                    <div 
                        className={`pass-option-card popular ${selectedPass === 'monthly' ? 'selected' : ''}`}
                        onClick={() => setSelectedPass('monthly')}
                        style={{ borderColor: selectedPass === 'monthly' ? passOptions.monthly.color : '#E5E7EB' }}
                    >
                        <div className="popular-badge">{passOptions.monthly.badge}</div>
                        <div className="pass-option-icon" style={{ background: `${passOptions.monthly.color}20` }}>
                            <span style={{ color: passOptions.monthly.color }}>{passOptions.monthly.icon}</span>
                        </div>
                        <h3>{passOptions.monthly.name}</h3>
                        <div className="pass-option-price">R{passOptions.monthly.price}</div>
                        <div className="pass-option-applications">
                            <strong>{passOptions.monthly.applications}</strong> applications
                        </div>
                        <div className="pass-savings-tag">{passOptions.monthly.savings}</div>
                        <p className="pass-option-description">{passOptions.monthly.description}</p>
                        <ul className="pass-features">
                            <li>✓ 30 applications</li>
                            <li>✓ Valid for 30 days</li>
                            <li>✓ Best for active job seekers</li>
                        </ul>
                        <button 
                            className={`pass-select-btn ${selectedPass === 'monthly' ? 'selected' : ''}`}
                            style={{ 
                                background: selectedPass === 'monthly' ? passOptions.monthly.color : '#F3F4F6',
                                color: selectedPass === 'monthly' ? 'white' : '#4B5563'
                            }}
                        >
                            {selectedPass === 'monthly' ? '✓ Selected' : 'Select'}
                        </button>
                    </div>

                    {/* Annual Pass */}
                    <div 
                        className={`pass-option-card ${selectedPass === 'annual' ? 'selected' : ''}`}
                        onClick={() => setSelectedPass('annual')}
                        style={{ borderColor: selectedPass === 'annual' ? passOptions.annual.color : '#E5E7EB' }}
                    >
                        <div className="pass-option-badge">{passOptions.annual.badge}</div>
                        <div className="pass-option-icon" style={{ background: `${passOptions.annual.color}20` }}>
                            <span style={{ color: passOptions.annual.color }}>{passOptions.annual.icon}</span>
                        </div>
                        <h3>{passOptions.annual.name}</h3>
                        <div className="pass-option-price">R{passOptions.annual.price}</div>
                        <div className="pass-option-applications">
                            <strong>{passOptions.annual.applications}</strong> applications
                        </div>
                        <div className="pass-savings-tag highlight">{passOptions.annual.savings}</div>
                        <p className="pass-option-description">{passOptions.annual.description}</p>
                        <ul className="pass-features">
                            <li>✓ Unlimited applications</li>
                            <li>✓ Valid for 365 days</li>
                            <li>✓ Only R30/month</li>
                        </ul>
                        <button 
                            className={`pass-select-btn ${selectedPass === 'annual' ? 'selected' : ''}`}
                            style={{ 
                                background: selectedPass === 'annual' ? passOptions.annual.color : '#F3F4F6',
                                color: selectedPass === 'annual' ? 'white' : '#4B5563'
                            }}
                        >
                            {selectedPass === 'annual' ? '✓ Selected' : 'Select'}
                        </button>
                    </div>
                </div>

                {/* Selected Pass Summary */}
                <div className="selected-pass-summary">
                    <h3>Order Summary</h3>
                    <div className="summary-row">
                        <span>Selected Pass:</span>
                        <strong>{passOptions[selectedPass].name}</strong>
                    </div>
                    <div className="summary-row">
                        <span>Applications:</span>
                        <strong>{passOptions[selectedPass].applications}</strong>
                    </div>
                    {selectedPass === 'annual' && (
                        <div className="summary-row savings">
                            <span>You Save:</span>
                            <strong className="save-amount">R240 (40% off)</strong>
                        </div>
                    )}
                    <div className="summary-row total">
                        <span>Total:</span>
                        <strong className="total-amount">R{passOptions[selectedPass].price}</strong>
                    </div>
                    {calculateSavings() && (
                        <div className="savings-message">
                            💡 {calculateSavings()}
                        </div>
                    )}
                </div>

                {/* Payment Section - Demo Only */}
                <div className="payment-section-demo">
                    <h4>Payment Method (Demo Mode)</h4>
                    <div className="payment-info-demo">
                        <div className="eft-demo-info">
                            <span className="demo-icon">🏦</span>
                            <div>
                                <strong>EFT / Bank Transfer</strong>
                                <p>For demonstration purposes, only EFT is available</p>
                            </div>
                        </div>
                        <div className="bank-details-demo">
                            <p><strong>Bank:</strong> FNB</p>
                            <p><strong>Account Name:</strong> KasiConnect (Pty) Ltd</p>
                            <p><strong>Account Number:</strong> 62849512678</p>
                            <p><strong>Reference:</strong> PASS-{Date.now()}</p>
                        </div>
                        <div className="demo-notice">
                            ⚡ This is a demo. No actual payment will be processed.
                        </div>
                    </div>
                </div>

                {/* Action Buttons */}
                <div className="purchase-actions">
                    <button className="btn-cancel" onClick={() => navigate('/dashboard')}>
                        Cancel
                    </button>
                    <button 
                        className="btn-purchase-pass"
                        onClick={handlePurchase}
                        disabled={loading}
                    >
                        {loading ? 'Processing...' : `Purchase Pass for R${passOptions[selectedPass].price}`}
                    </button>
                </div>

                {/* Trust Badges */}
                <div className="trust-badges">
                    <div className="trust-badge">
                        <span>🔒</span>
                        <span>Secure Payment</span>
                    </div>
                    <div className="trust-badge">
                        <span>⚡</span>
                        <span>Instant Access</span>
                    </div>
                    <div className="trust-badge">
                        <span>💯</span>
                        <span>Satisfaction Guaranteed</span>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default VoucherPurchase;
